# [v40 NEW] Byte-Pair Encoding (BPE) Tokenizer
class BPETokenizer:
    def __init__(self):
        self.merges = {} 
        self.vocab = {}  
        self.vocab_size = 0

    def get_stats(self, ids):
        counts = {}
        for pair in zip(ids, ids[1:]):
            counts[pair] = counts.get(pair, 0) + 1
        return counts

    def merge(self, ids, pair, idx):
        newids = []
        i = 0
        while i < len(ids):
            if i < len(ids) - 1 and ids[i] == pair[0] and ids[i+1] == pair[1]:
                newids.append(idx)
                i += 2
            else:
                newids.append(ids[i])
                i += 1
        return newids

    def train(self, text, vocab_size=None):
        # 1. Convert text to raw bytes (integers 0-255)
        ids = list(text.encode("utf-8"))
        
        # If no size provided, auto-detect based on complexity
        if vocab_size is None:
            # Heuristic ceiling
            approx_words = len(set(re.findall(r"[\w']+|[^\s\w]", text)))
            target_merges = approx_words + 500 
        else:
            target_merges = vocab_size - 256

        print(f"Auto-BPE: Scanning for patterns...")

        for i in range(target_merges):
            stats = self.get_stats(ids)
            if not stats: break 
            
            pair = max(stats, key=stats.get)
            
            # [Auto-Stop] If best pair appears < 2 times, it's not a pattern
            if stats[pair] < 2:
                print(f"Auto-BPE: Natural convergence at step {i}.")
                break
            
            idx = 256 + i
            ids = self.merge(ids, pair, idx)
            self.merges[pair] = idx
            
        self.vocab_size = 256 + len(self.merges)
        print(f"BPE Training Complete. Final Vocab Size: {self.vocab_size}")

    def encode(self, text):
        ids = list(text.encode("utf-8"))
        while len(ids) >= 2:
            stats = self.get_stats(ids)
            pair = min(stats, key=lambda p: self.merges.get(p, float("inf")))
            if pair not in self.merges: break 
            idx = self.merges[pair]
            ids = self.merge(ids, pair, idx)
        return torch.tensor(ids, dtype=torch.long).to(DEVICE)

    def decode(self, ids):
        vocab = {idx: bytes([idx]) for idx in range(256)}
        for (p0, p1), idx in self.merges.items():
            vocab[idx] = vocab[p0] + vocab[p1]
        
        if isinstance(ids, torch.Tensor): ids = ids.tolist()
        if isinstance(ids, int): ids = [ids]
            
        res = b"".join(vocab.get(idx, b"") for idx in ids)
        return res.decode("utf-8", errors="replace")

# [v40 Setup] Initialize BPE
tokenizer = BPETokenizer()
tokenizer.train(TEXT_DATA)
data_tensor = tokenizer.encode(TEXT_DATA)
vocab_size = tokenizer.vocab_size

print(f"First 10 token IDs: {data_tensor[:10].tolist()}")
